 Here's an example C++ function that takes a reference to a string containing markdown formatted text and returns a string containing the corresponding HTML formatted text:

```cpp
#include <string>
#include <iostream>
#include <sstream>

std::string md2html(std::string &markdown) {
    std::stringstream ss(markdown);
    std::string item;
    while (std::getline(ss, item, '#')) {
        // Skip the hash symbol and rest of the line
        ss.setstate(std::ios_base::skipws);
        ss >> item;
        ss.setstate(std::ios_base::in);
        ss.unget();
        // Parse the item as markdown
        std::string md = item;
        // Replace all occurrences of * with <strong>
        md = md.replace("*", "<strong>");
        // Replace all occurrences of _ with <em>
        md = md.replace("_", "<em>");
        // Replace all occurrences of - with <strong>
        md = md.replace("-", "<strong>");
        // Replace all occurrences of + with <em>
        md = md.replace("+", "<em>");
        // Replace all occurrences of = with <strong>
        md = md.replace("=", "<strong>");
        // Replace all occurrences of ~ with <em>
        md = md.replace("~", "<em>");
        // Replace all occurrences of ` with <em>
        md = md.replace("`", "<em>");
        // Replace all occurrences of'with <em>
        md = md.replace("'", "<em>");
        // Replace all occurrences of { with <code>
        md = md.replace("{", "<code>");
        // Replace all occurrences of } with </code>
        md = md.replace("}", "</code>");
        // Append the resulting HTML to the output string
        std::string html = "<p>" + md + "</p>";
        std::cout << html << std::endl;
    }
    return markdown;
}
```

